def _tokenize_str(s: str) -> List[_PrettyToken]:
    tokens = []
    l = 0
    while l < len(s):
        r = l + 1
        while r < len(s) and (s[l] in ' \t') == (s[r] in ' \t'):
            r += 1
        if s[l] in ' \t':
            typ = _PrettyTokenType.WHITESPACE
        else:
            typ = _PrettyTokenType.BODY
        tokens.append(_PrettyToken(typ, s[l:r]))
        l = r
    return tokens

